	public void UpdateState(NewsArticle article, int targetNum, int totalNum, bool notificationOn)
	{
		((Control)PageNum).Visible = true;
		((Control)PageText).Visible = true;
		((Control)ShareTime).Visible = true;
		((Control)Author).Visible = true;
		PageName.Text = article.Title;
		PageText.SetMarkupPermissive(article.Content);
		PageNum.Text = $"{targetNum}/{totalNum}";
		NotificationSwitch.Text = Loc.GetString(notificationOn ? "news-read-ui-notification-on" : "news-read-ui-notification-off");
		string text = article.ShareTime.ToString("hh\\:mm\\:ss");
		ShareTime.SetMarkup(Loc.GetString("news-read-ui-time-prefix-text") + " " + text);
		Author.SetMarkup(Loc.GetString("news-read-ui-author-prefix") + " " + ((article.Author != null) ? article.Author : Loc.GetString("news-read-ui-no-author")));
		((BaseButton)Prev).Disabled = targetNum <= 1;
		((BaseButton)Next).Disabled = targetNum >= totalNum;
	}

	public void UpdateEmptyState(bool notificationOn)
	{
		((Control)PageNum).Visible = false;
		((Control)PageText).Visible = false;
		((Control)ShareTime).Visible = false;
		((Control)Author).Visible = false;
		PageName.Text = Loc.GetString("news-read-ui-not-found-text");
		NotificationSwitch.Text = Loc.GetString(notificationOn ? "news-read-ui-notification-on" : "news-read-ui-notification-off");
	}

